INSERT INTO TB_STRUCT_DIAG_DETAIL (
	DIAG_ID, SEQ, TABLE_NM, COLUMN_NM, CHANGE_TYPE,
	PREV_DATA_TYPE, CURR_DATA_TYPE, PREV_DATA_LEN, CURR_DATA_LEN,
	PREV_NULLABLE, CURR_NULLABLE
) VALUES (
	#{diagId}, #{seq}, #{tableNm}, #{columnNm}, #{changeType},
	#{prevDataType}, #{currDataType}, #{prevDataLen}, #{currDataLen},
	#{prevNullable}, #{currNullable}
)

mapper.select:
SELECT DIAG_ID, DS_ID, SCHEMA_NM, DIAG_DT, ADDED_TABLES + ADDED_COLUMNS + MODIFIED_COLUMNS + DELETED_TABLES + DELETED_COLUMNS AS TOTAL_CHANGES, TOTAL_TABLES, TOTAL_COLUMNS, ADDED_TABLES, ADDED_COLUMNS, MODIFIED_COLUMNS, DELETED_TABLES, DELETED_COLUMNS, CRET_USER_ID FROM TB_STRUCT_DIAG_HISTORY WHERE DS_ID = #{dsId}
AND SCHEMA_NM = #{schemaNm}
ORDER BY DIAG_DT DESC LIMIT 1
